SELECT station_name, location, country, institution_id, COUNT(*) OVER () as total_stations
FROM research_stations
WHERE country = 'USA';

SELECT project_name, COUNT(DISTINCT institution_id) AS num_institutions
FROM projects
GROUP BY project_name;

SELECT COUNT(*) AS total_research_stations
FROM research_stations
WHERE country = 'USA';

SELECT country, COUNT(station_id) AS station_count
FROM research_stations
GROUP BY country;

SELECT MAX(project_count) AS max_projects
FROM (
  SELECT COUNT(project_id) AS project_count
  FROM projects
  GROUP BY institution_id
);
